```java
// product-service (port 8081, separate Maven project)
@SpringBootApplication
public class ProductServiceApplication {
    public static void main(String[] args) { SpringApplication.run(ProductServiceApplication.class, args); }
}

@Entity class Product {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    String name; double price; int stock;
    protected Product(){}
    Product(String n, double p, int s) { name=n; price=p; stock=s; }
    // getters...
}

@RestController @RequestMapping("/api/products")
class ProductController {
    private final ProductRepository repo;
    ProductController(ProductRepository r) { repo=r; }

    @GetMapping("/{id}")
    ResponseEntity<Product> getById(@PathVariable String id) {
        return repo.findById(id).map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping("/{id}/availability")
    Map<String,Object> checkAvailability(@PathVariable String id,
                                          @RequestParam int quantity) {
        return repo.findById(id)
            .map(p -> Map.of(
                "available", p.getStock() >= quantity,
                "stock", p.getStock()))
            .orElse(Map.of("available", false, "stock", 0));
    }
}
// application.properties: server.port=8081
```

```java
// order-service (port 8082, separate Maven project)
@SpringBootApplication
public class OrderServiceApplication {
    public static void main(String[] args) { SpringApplication.run(OrderServiceApplication.class, args); }
}

@Configuration
class AppConfig {
    @Bean RestTemplate restTemplate() { return new RestTemplate(); }
}

@Service
class OrderService {
    private final RestTemplate restTemplate;
    private final OrderRepository orderRepo;
    private static final String PRODUCT_SERVICE_URL = "http://localhost:8081";

    OrderService(RestTemplate rt, OrderRepository r) { restTemplate=rt; orderRepo=r; }

    public Order placeOrder(String productId, int quantity) {
        // Call product-service to check availability:
        @SuppressWarnings("unchecked")
        Map<String,Object> availability = restTemplate.getForObject(
            PRODUCT_SERVICE_URL + "/api/products/" + productId + "/availability?quantity=" + quantity,
            Map.class);

        boolean available = Boolean.TRUE.equals(availability.get("available"));
        if (!available) {
            throw new InsufficientStockException(
                "Product " + productId + " has insufficient stock");
        }
        return orderRepo.save(new Order(productId, quantity));
    }
}
// application.properties: server.port=8082
```

